+                crate::Error::Wezterm(WeztermError::SocketNotFound(path)) => {
+                    assert_eq!(path, bogus.to_string_lossy());
+                }
+                other => panic!("UnifiedClient expected SocketNotFound (kill), got {other:?}"),
+            }
+        });
+    }
